-- ============================================
-- CONSOLIDATED DATABASE SCHEMA
-- Negotiation Experiment Platform (Self-Hosted PostgreSQL)
-- ============================================
--
-- This file is a single consolidated migration for running on plain
-- PostgreSQL 16+ (no Supabase). It was generated by concatenating
-- migrations 001 through 023 in order, with the following removals:
--
--   - ALTER PUBLICATION supabase_realtime ...  (Supabase-only)
--   - ALTER TABLE ... ENABLE ROW LEVEL SECURITY (Supabase-only)
--   - CREATE POLICY / DROP POLICY ...          (Supabase-only)
--
-- Functions that were replaced by later migrations still appear in
-- order; the OR REPLACE clause makes this safe.
--
-- Run on a fresh database:
--   psql -U postgres -d your_db -f init.sql
-- ============================================


-- ============================================================
-- Migration 001: Initial Schema
-- ============================================================

-- Enable UUID extension (works on plain PostgreSQL)
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ============================================
-- 1. PARTICIPANTS TABLE
-- Stores participant information and questionnaire data
-- ============================================
CREATE TABLE participants (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    email TEXT UNIQUE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    demographic_data JSONB DEFAULT '{}'::jsonb,
    pre_questionnaire_data JSONB DEFAULT '{}'::jsonb,
    post_questionnaire_data JSONB DEFAULT '{}'::jsonb
);

COMMENT ON TABLE participants IS 'Stores participant information and survey responses';
COMMENT ON COLUMN participants.demographic_data IS 'Demographics collected during pre-survey (age, gender, education, etc.)';
COMMENT ON COLUMN participants.pre_questionnaire_data IS 'Pre-negotiation survey responses';
COMMENT ON COLUMN participants.post_questionnaire_data IS 'Post-negotiation survey responses';

-- ============================================
-- 2. SESSIONS TABLE
-- Stores negotiation session metadata
-- ============================================
CREATE TABLE sessions (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    session_code TEXT UNIQUE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    started_at TIMESTAMPTZ,
    ended_at TIMESTAMPTZ,
    status TEXT DEFAULT 'waiting' CHECK (status IN ('waiting', 'active', 'completed', 'cancelled')),
    negotiation_scenario TEXT,
    time_limit_minutes INTEGER DEFAULT 20,
    agreement_reached BOOLEAN,
    final_agreement JSONB DEFAULT '{}'::jsonb
);

ALTER TABLE sessions ADD CONSTRAINT session_code_length CHECK (char_length(session_code) = 6);

COMMENT ON TABLE sessions IS 'Negotiation session metadata and configuration';
COMMENT ON COLUMN sessions.session_code IS '6-character unique code for participants to join';
COMMENT ON COLUMN sessions.status IS 'Session state: waiting, active, completed, or cancelled';
COMMENT ON COLUMN sessions.final_agreement IS 'JSON containing the final negotiated terms if agreement reached';

-- ============================================
-- 3. SESSION_PARTICIPANTS TABLE
-- Junction table linking participants to sessions with roles
-- ============================================
CREATE TABLE session_participants (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    session_id UUID NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
    participant_id UUID NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
    role TEXT NOT NULL CHECK (role IN ('pm', 'developer')),
    joined_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE (session_id, participant_id)
);

COMMENT ON TABLE session_participants IS 'Links participants to sessions with their assigned roles';
COMMENT ON COLUMN session_participants.role IS 'Negotiation role: pm (Project Manager) or developer';

-- ============================================
-- 4. MESSAGES TABLE
-- Stores all chat/negotiation messages
-- ============================================
CREATE TABLE messages (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    session_id UUID NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
    participant_id UUID NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
    content TEXT NOT NULL,
    message_type TEXT DEFAULT 'negotiation' CHECK (message_type IN ('negotiation', 'offer', 'acceptance', 'rejection', 'system')),
    timestamp TIMESTAMPTZ DEFAULT NOW(),
    metadata JSONB DEFAULT '{}'::jsonb
);

COMMENT ON TABLE messages IS 'All messages exchanged during negotiation sessions';
COMMENT ON COLUMN messages.message_type IS 'Type of message: negotiation (regular chat), offer, acceptance, rejection, system';
COMMENT ON COLUMN messages.metadata IS 'Additional data like offer details, typing duration, etc.';

-- ============================================
-- 5. ASSISTANT_QUERIES TABLE
-- Logs all AI assistant interactions
-- ============================================
CREATE TABLE assistant_queries (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    session_id UUID NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
    participant_id UUID NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
    query_text TEXT NOT NULL,
    response_text TEXT NOT NULL,
    timestamp TIMESTAMPTZ DEFAULT NOW(),
    tokens_used INTEGER,
    response_time_ms INTEGER
);

COMMENT ON TABLE assistant_queries IS 'Logs all interactions with the AI negotiation assistant';
COMMENT ON COLUMN assistant_queries.tokens_used IS 'Total tokens (input + output) consumed by this query';
COMMENT ON COLUMN assistant_queries.response_time_ms IS 'API response time in milliseconds';

-- ============================================
-- 6. EVENT_LOG TABLE
-- Comprehensive event tracking for research analysis
-- ============================================
CREATE TABLE event_log (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    session_id UUID REFERENCES sessions(id) ON DELETE CASCADE,
    participant_id UUID REFERENCES participants(id) ON DELETE CASCADE,
    event_type TEXT NOT NULL,
    event_data JSONB NOT NULL DEFAULT '{}'::jsonb,
    timestamp TIMESTAMPTZ DEFAULT NOW()
);

COMMENT ON TABLE event_log IS 'Detailed event log for behavioral analysis';
COMMENT ON COLUMN event_log.event_type IS 'Event types: page_view, button_click, offer_made, message_sent, assistant_opened, etc.';
COMMENT ON COLUMN event_log.event_data IS 'Event-specific data payload';

-- ============================================
-- 7. NEGOTIATION_OUTCOMES TABLE
-- Stores computed outcome metrics for analysis
-- ============================================
CREATE TABLE negotiation_outcomes (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    session_id UUID NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
    participant_id UUID NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
    individual_points INTEGER,
    joint_gain INTEGER,
    agreement_rate BOOLEAN,
    time_to_agreement_seconds INTEGER,
    pareto_gap NUMERIC(10, 4),
    behavioral_reliance_score NUMERIC(10, 4),
    query_frequency INTEGER,
    incorporation_score NUMERIC(10, 4),
    created_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE (session_id, participant_id)
);

COMMENT ON TABLE negotiation_outcomes IS 'Computed negotiation outcome metrics for research analysis';
COMMENT ON COLUMN negotiation_outcomes.individual_points IS 'Points earned by this participant based on payoff matrix';
COMMENT ON COLUMN negotiation_outcomes.joint_gain IS 'Combined points for both participants';
COMMENT ON COLUMN negotiation_outcomes.pareto_gap IS 'Distance from Pareto-optimal outcome (0 = optimal)';
COMMENT ON COLUMN negotiation_outcomes.behavioral_reliance_score IS 'Measure of reliance on AI assistant suggestions';
COMMENT ON COLUMN negotiation_outcomes.query_frequency IS 'Number of AI assistant queries made';
COMMENT ON COLUMN negotiation_outcomes.incorporation_score IS 'Degree to which AI suggestions were incorporated';

-- ============================================
-- INDEXES
-- ============================================

CREATE INDEX idx_sessions_status ON sessions(status);
CREATE INDEX idx_sessions_code ON sessions(session_code);

CREATE INDEX idx_session_participants_session ON session_participants(session_id);
CREATE INDEX idx_session_participants_participant ON session_participants(participant_id);

CREATE INDEX idx_messages_session ON messages(session_id);
CREATE INDEX idx_messages_participant ON messages(participant_id);
CREATE INDEX idx_messages_timestamp ON messages(timestamp);
CREATE INDEX idx_messages_session_timestamp ON messages(session_id, timestamp);

CREATE INDEX idx_assistant_queries_session ON assistant_queries(session_id);
CREATE INDEX idx_assistant_queries_participant ON assistant_queries(participant_id);

CREATE INDEX idx_event_log_session ON event_log(session_id);
CREATE INDEX idx_event_log_participant ON event_log(participant_id);
CREATE INDEX idx_event_log_timestamp ON event_log(timestamp);
CREATE INDEX idx_event_log_type ON event_log(event_type);

CREATE INDEX idx_negotiation_outcomes_session ON negotiation_outcomes(session_id);
CREATE INDEX idx_negotiation_outcomes_participant ON negotiation_outcomes(participant_id);

-- ============================================
-- HELPER FUNCTIONS
-- ============================================

-- Generate a random 6-character session code
CREATE OR REPLACE FUNCTION generate_session_code()
RETURNS TEXT AS $$
DECLARE
    chars TEXT := 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    result TEXT := '';
    i INTEGER;
BEGIN
    FOR i IN 1..6 LOOP
        result := result || substr(chars, floor(random() * length(chars) + 1)::integer, 1);
    END LOOP;
    RETURN result;
END;
$$ LANGUAGE plpgsql;

COMMENT ON FUNCTION generate_session_code IS 'Generates a random 6-character alphanumeric code (excludes confusing chars like 0, O, 1, I)';

-- Create a new session with auto-generated code
CREATE OR REPLACE FUNCTION create_session(scenario TEXT DEFAULT NULL, time_limit INTEGER DEFAULT 20)
RETURNS sessions AS $$
DECLARE
    new_code TEXT;
    new_session sessions;
BEGIN
    LOOP
        new_code := generate_session_code();
        EXIT WHEN NOT EXISTS (SELECT 1 FROM sessions WHERE session_code = new_code);
    END LOOP;
    
    INSERT INTO sessions (session_code, negotiation_scenario, time_limit_minutes)
    VALUES (new_code, scenario, time_limit)
    RETURNING * INTO new_session;
    
    RETURN new_session;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION create_session IS 'Creates a new session with auto-generated unique code';


-- ============================================================
-- Migration 002: Lab Mode RLS
-- (All RLS policies removed for self-hosted; no-op)
