-- ============================================================
-- Migration 003: Participant Tokens
-- ============================================================

CREATE TABLE IF NOT EXISTS participant_tokens (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    token TEXT UNIQUE NOT NULL,
    session_id UUID REFERENCES sessions(id) ON DELETE CASCADE,
    participant_id UUID REFERENCES participants(id) ON DELETE SET NULL,
    role TEXT CHECK (role IN ('pm', 'developer')),
    terminal_number INTEGER,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    claimed_at TIMESTAMP WITH TIME ZONE,
    metadata JSONB DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_participant_tokens_token ON participant_tokens(token);
CREATE INDEX IF NOT EXISTS idx_participant_tokens_session ON participant_tokens(session_id);

-- Generate a short, readable token
CREATE OR REPLACE FUNCTION generate_participant_token()
RETURNS TEXT AS $$
DECLARE
    chars TEXT := 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    result TEXT := '';
    i INTEGER;
BEGIN
    FOR i IN 1..5 LOOP
        result := result || substr(chars, floor(random() * length(chars) + 1)::int, 1);
    END LOOP;
    RETURN result;
END;
$$ LANGUAGE plpgsql;

-- Create a batch of tokens for a session (PM + Developer)
CREATE OR REPLACE FUNCTION create_token_batch(
    p_session_id UUID
)
RETURNS TABLE (
    token TEXT,
    role TEXT,
    url TEXT
) AS $$
DECLARE
    new_token TEXT;
    base_url TEXT := '';
BEGIN
    new_token := generate_participant_token();
    INSERT INTO participant_tokens (token, session_id, role)
    VALUES (new_token, p_session_id, 'pm');
    token := new_token;
    role := 'pm';
    url := '/p/' || new_token;
    RETURN NEXT;
    
    new_token := generate_participant_token();
    INSERT INTO participant_tokens (token, session_id, role)
    VALUES (new_token, p_session_id, 'developer');
    token := new_token;
    role := 'developer';
    url := '/p/' || new_token;
    RETURN NEXT;
END;
$$ LANGUAGE plpgsql;


