-- ============================================================
-- Migration 005: Survey Flow Tracking
-- ============================================================

ALTER TABLE session_participants 
ADD COLUMN IF NOT EXISTS pre_survey_completed_at TIMESTAMPTZ DEFAULT NULL;

CREATE INDEX IF NOT EXISTS idx_session_participants_pre_survey 
ON session_participants(session_id, pre_survey_completed_at);

-- Check if both participants have completed pre-survey
CREATE OR REPLACE FUNCTION check_both_surveys_complete(p_session_id UUID)
RETURNS BOOLEAN AS $$
DECLARE
  total_participants INTEGER;
  completed_surveys INTEGER;
BEGIN
  SELECT COUNT(*), COUNT(pre_survey_completed_at)
  INTO total_participants, completed_surveys
  FROM session_participants
  WHERE session_id = p_session_id;
  
  RETURN total_participants = 2 AND completed_surveys = 2;
END;
$$ LANGUAGE plpgsql;

COMMENT ON COLUMN session_participants.pre_survey_completed_at IS 
  'Timestamp when participant completed the pre-negotiation survey. NULL if not yet completed.';


