COMMENT ON TABLE round_queue IS 'Participants waiting to be matched for a given round (1, 2, or 3)';
CREATE INDEX IF NOT EXISTS idx_round_queue_round_number ON round_queue(round_number);
CREATE INDEX IF NOT EXISTS idx_round_queue_participant ON round_queue(participant_id);


-- ============================================================
-- Migration 008: Matchmaking RPC
-- ============================================================

CREATE OR REPLACE FUNCTION try_match_round(p_participant_id UUID, p_round_number INTEGER)
RETURNS TABLE(session_id UUID, session_code TEXT, role TEXT, dyad_id UUID) AS $$
DECLARE
  v_dyad_id UUID;
  v_session_code TEXT;
  v_session_id UUID;
  v_my_role TEXT;
  v_partner_id UUID;
  v_scenario TEXT;
  v_treatment_self TEXT;
  v_treatment_partner TEXT;
BEGIN
  IF p_round_number < 1 OR p_round_number > 3 THEN
    RETURN;
  END IF;

  INSERT INTO round_queue (participant_id, round_number)
  VALUES (p_participant_id, p_round_number)
  ON CONFLICT (participant_id, round_number) DO NOTHING;

  v_scenario := CASE p_round_number
    WHEN 1 THEN 'v1.a'
    WHEN 2 THEN 'v1.b'
    WHEN 3 THEN 'v1.c'
    ELSE 'v1.a'
  END;

  SELECT rq.participant_id INTO v_partner_id
  FROM round_queue rq
  WHERE rq.round_number = p_round_number
    AND rq.participant_id <> p_participant_id
    AND NOT EXISTS (
      SELECT 1
      FROM session_participants sp_me
      JOIN session_participants sp_other ON sp_me.session_id = sp_other.session_id
        AND sp_other.participant_id = rq.participant_id
      JOIN sessions s ON s.id = sp_me.session_id
      WHERE sp_me.participant_id = p_participant_id
        AND s.round_number IS NOT NULL
        AND s.round_number < p_round_number
    )
  LIMIT 1
  FOR UPDATE SKIP LOCKED;

  IF v_partner_id IS NULL THEN
    RETURN;
  END IF;

  v_dyad_id := uuid_generate_v4();

  LOOP
    v_session_code := generate_session_code();
    EXIT WHEN NOT EXISTS (SELECT 1 FROM sessions WHERE sessions.session_code = v_session_code);
  END LOOP;

  INSERT INTO sessions (
    session_code, status, negotiation_scenario, time_limit_minutes,
    dyad_id, round_number
  )
  VALUES (
    v_session_code, 'waiting', v_scenario, 45,
    v_dyad_id, p_round_number
  )
  RETURNING id INTO v_session_id;

  v_my_role := 'pm';
  v_treatment_self := 'payoff_always_visible';
  v_treatment_partner := 'payoff_collapsible';

  INSERT INTO session_participants (session_id, participant_id, role, treatment_condition)
  VALUES
    (v_session_id, p_participant_id, v_my_role, v_treatment_self),
    (v_session_id, v_partner_id, 'developer', v_treatment_partner);

  DELETE FROM round_queue
  WHERE (participant_id = p_participant_id OR participant_id = v_partner_id)
    AND round_number = p_round_number;

  session_id := v_session_id;
  session_code := v_session_code;
  role := v_my_role;
  dyad_id := v_dyad_id;
  RETURN NEXT;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION try_match_round IS 'Attempt to match participant for round N; returns session and role if matched, else no row';


-- ============================================================
-- Migration 009: Pair-Based Rounds
-- ============================================================

ALTER TABLE sessions
ADD COLUMN IF NOT EXISTS pair_session_id UUID DEFAULT NULL;

ALTER TABLE sessions
ADD CONSTRAINT fk_sessions_pair_session
FOREIGN KEY (pair_session_id) REFERENCES sessions(id) ON DELETE SET NULL;

COMMENT ON COLUMN sessions.pair_session_id IS 'Links round session to the pair/join session where participants did pre-survey';

CREATE INDEX IF NOT EXISTS idx_sessions_pair_session_id ON sessions(pair_session_id);

ALTER TABLE participants
ADD COLUMN IF NOT EXISTS post_round_survey_data JSONB DEFAULT '{}'::jsonb;

COMMENT ON COLUMN participants.post_round_survey_data IS 'Post-round survey responses keyed by round: {"1":{"opponent_priority_guess":"I2"},"2":{...},"3":{...}}';

-- Creates a round session for the pair; same 2 participants, roles preserved
CREATE OR REPLACE FUNCTION create_round_for_pair(p_pair_session_id UUID, p_round_number INTEGER)
RETURNS UUID AS $$
DECLARE
  v_dyad_id UUID;
  v_session_code TEXT;
  v_session_id UUID;
  v_scenario TEXT;
  v_participant1_id UUID;
  v_participant2_id UUID;
  v_role1 TEXT;
  v_role2 TEXT;
  v_treatment1 TEXT;
  v_treatment2 TEXT;
BEGIN
  IF p_round_number < 1 OR p_round_number > 3 THEN
    RAISE EXCEPTION 'round_number must be 1, 2, or 3';
  END IF;

  SELECT participant_id, role
  INTO v_participant1_id, v_role1
  FROM session_participants
  WHERE session_id = p_pair_session_id
  ORDER BY joined_at ASC
  LIMIT 1;

  SELECT participant_id, role
  INTO v_participant2_id, v_role2
  FROM session_participants
  WHERE session_id = p_pair_session_id
  ORDER BY joined_at ASC
  OFFSET 1 LIMIT 1;

  IF v_participant1_id IS NULL OR v_participant2_id IS NULL THEN
    RAISE EXCEPTION 'Pair session must have exactly 2 participants';
  END IF;

  v_scenario := CASE p_round_number
    WHEN 1 THEN 'v1.a'
    WHEN 2 THEN 'v1.b'
    WHEN 3 THEN 'v1.c'
    ELSE 'v1.a'
  END;

  v_dyad_id := uuid_generate_v4();

  LOOP
    v_session_code := generate_session_code();
    EXIT WHEN NOT EXISTS (SELECT 1 FROM sessions WHERE sessions.session_code = v_session_code);
  END LOOP;

  v_treatment1 := 'payoff_always_visible';
  v_treatment2 := 'payoff_collapsible';

  INSERT INTO sessions (
    session_code, status, negotiation_scenario, time_limit_minutes,
    dyad_id, round_number, pair_session_id
  )
  VALUES (
    v_session_code, 'waiting', v_scenario, 45,
    v_dyad_id, p_round_number, p_pair_session_id
  )
  RETURNING id INTO v_session_id;

  INSERT INTO session_participants (session_id, participant_id, role, treatment_condition)
  VALUES
    (v_session_id, v_participant1_id, COALESCE(v_role1, 'pm'), v_treatment1),
    (v_session_id, v_participant2_id, COALESCE(v_role2, 'developer'), v_treatment2);

  RETURN v_session_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION create_round_for_pair IS 'Creates a round session for a pair; same 2 participants, payoff v1.a/b/c by round';


-- ============================================================
-- Migration 010: Experiment Batches
-- ============================================================

CREATE TABLE IF NOT EXISTS experiment_batches (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    batch_code TEXT UNIQUE NOT NULL,
    max_participants INTEGER NOT NULL DEFAULT 20,
    status TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open', 'closed')),
    created_at TIMESTAMPTZ DEFAULT NOW()
);

COMMENT ON TABLE experiment_batches IS 'Batch (experiment run) for pool-based matchmaking; up to 20 participants per batch';
COMMENT ON COLUMN experiment_batches.batch_code IS '6-char code participants enter to join the batch';

CREATE UNIQUE INDEX IF NOT EXISTS idx_experiment_batches_batch_code ON experiment_batches(batch_code);

CREATE TABLE IF NOT EXISTS batch_participants (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    batch_id UUID NOT NULL REFERENCES experiment_batches(id) ON DELETE CASCADE,
    participant_id UUID NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
    condition_order JSONB NOT NULL,
    joined_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE (batch_id, participant_id)
);

COMMENT ON TABLE batch_participants IS 'Participants in a batch with assigned condition order (permutation of v1.a, v1.b, v1.c)';
COMMENT ON COLUMN batch_participants.condition_order IS 'JSON array of 3 scenario keys, e.g. ["v1.a","v1.b","v1.c"] for Round A then B then C';

CREATE INDEX IF NOT EXISTS idx_batch_participants_batch_id ON batch_participants(batch_id);
CREATE INDEX IF NOT EXISTS idx_batch_participants_participant_id ON batch_participants(participant_id);

-- Create a new experiment batch with unique 6-char code
CREATE OR REPLACE FUNCTION create_batch(p_max_participants INTEGER DEFAULT 20)
RETURNS experiment_batches AS $$
DECLARE
    v_batch_code TEXT;
    v_batch experiment_batches;
BEGIN
    LOOP
        v_batch_code := generate_session_code();
        EXIT WHEN NOT EXISTS (SELECT 1 FROM sessions WHERE session_code = v_batch_code)
          AND NOT EXISTS (SELECT 1 FROM experiment_batches WHERE batch_code = v_batch_code);
    END LOOP;

    INSERT INTO experiment_batches (batch_code, max_participants, status)
    VALUES (v_batch_code, p_max_participants, 'open')
    RETURNING * INTO v_batch;
    RETURN v_batch;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION create_batch IS 'Creates a new experiment batch with unique 6-char code';

-- Pool matchmaking: pairs two participants in same batch, same condition, no past opponent
CREATE OR REPLACE FUNCTION try_match_pool_round(p_participant_id UUID, p_slot_index INTEGER)
RETURNS TABLE(session_id UUID, session_code TEXT, role TEXT, dyad_id UUID) AS $$
DECLARE
    v_batch_id UUID;
    v_my_condition TEXT;
    v_partner_id UUID;
    v_dyad_id UUID;
    v_session_code TEXT;
    v_session_id UUID;
    v_my_role TEXT;
    v_treatment_self TEXT;
    v_treatment_partner TEXT;
BEGIN
    IF p_slot_index < 1 OR p_slot_index > 3 THEN
        RETURN;
    END IF;

    SELECT bp.batch_id,
           bp.condition_order->>(p_slot_index - 1) INTO v_batch_id, v_my_condition
    FROM batch_participants bp
    WHERE bp.participant_id = p_participant_id
    LIMIT 1;

    IF v_batch_id IS NULL OR v_my_condition IS NULL OR v_my_condition = '' THEN
        RETURN;
    END IF;

    INSERT INTO round_queue (participant_id, round_number)
    VALUES (p_participant_id, p_slot_index)
    ON CONFLICT (participant_id, round_number) DO NOTHING;

    SELECT rq.participant_id INTO v_partner_id
    FROM round_queue rq
    JOIN batch_participants bp ON bp.participant_id = rq.participant_id AND bp.batch_id = v_batch_id
    WHERE rq.round_number = p_slot_index
      AND rq.participant_id <> p_participant_id
      AND (bp.condition_order->>(p_slot_index - 1)) = v_my_condition
      AND NOT EXISTS (
          SELECT 1
          FROM session_participants sp_me
          JOIN session_participants sp_other ON sp_me.session_id = sp_other.session_id
            AND sp_other.participant_id = rq.participant_id
          JOIN sessions s ON s.id = sp_me.session_id
          WHERE sp_me.participant_id = p_participant_id
            AND s.round_number IS NOT NULL
            AND s.round_number < p_slot_index
      )
    LIMIT 1
    FOR UPDATE OF rq SKIP LOCKED;

    IF v_partner_id IS NULL THEN
        RETURN;
    END IF;

    v_dyad_id := uuid_generate_v4();

    LOOP
        v_session_code := generate_session_code();
        EXIT WHEN NOT EXISTS (SELECT 1 FROM sessions WHERE sessions.session_code = v_session_code)
          AND NOT EXISTS (SELECT 1 FROM experiment_batches WHERE batch_code = v_session_code);
    END LOOP;

    INSERT INTO sessions (
        session_code, status, negotiation_scenario, time_limit_minutes,
        dyad_id, round_number
    )
    VALUES (
        v_session_code, 'waiting', v_my_condition, 45,
        v_dyad_id, p_slot_index
    )
    RETURNING id INTO v_session_id;

    v_my_role := 'pm';
    v_treatment_self := 'payoff_always_visible';
    v_treatment_partner := 'payoff_collapsible';

    INSERT INTO session_participants (session_id, participant_id, role, treatment_condition)
    VALUES
        (v_session_id, p_participant_id, v_my_role, v_treatment_self),
        (v_session_id, v_partner_id, 'developer', v_treatment_partner);

    DELETE FROM round_queue
    WHERE (participant_id = p_participant_id OR participant_id = v_partner_id)
      AND round_number = p_slot_index;

    session_id := v_session_id;
    session_code := v_session_code;
    role := v_my_role;
    dyad_id := v_dyad_id;
    RETURN NEXT;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION try_match_pool_round IS 'Pool matchmaking: match by (slot, condition), no past opponent; returns session and role if matched';


