-- create_round_for_pair — updated to 10 min per round
CREATE OR REPLACE FUNCTION create_round_for_pair(p_pair_session_id UUID, p_round_number INTEGER)
RETURNS UUID AS $$
DECLARE
  v_dyad_id UUID;
  v_session_code TEXT;
  v_session_id UUID;
  v_scenario TEXT;
  v_participant1_id UUID;
  v_participant2_id UUID;
  v_role1 TEXT;
  v_role2 TEXT;
  v_treatment1 TEXT;
  v_treatment2 TEXT;
BEGIN
  IF p_round_number < 1 OR p_round_number > 3 THEN
    RAISE EXCEPTION 'round_number must be 1, 2, or 3';
  END IF;

  SELECT participant_id, role
  INTO v_participant1_id, v_role1
  FROM session_participants
  WHERE session_id = p_pair_session_id
  ORDER BY joined_at ASC
  LIMIT 1;

  SELECT participant_id, role
  INTO v_participant2_id, v_role2
  FROM session_participants
  WHERE session_id = p_pair_session_id
  ORDER BY joined_at ASC
  OFFSET 1 LIMIT 1;

  IF v_participant1_id IS NULL OR v_participant2_id IS NULL THEN
    RAISE EXCEPTION 'Pair session must have exactly 2 participants';
  END IF;

  v_scenario := CASE p_round_number
    WHEN 1 THEN 'v1.a'
    WHEN 2 THEN 'v1.b'
    WHEN 3 THEN 'v1.c'
    ELSE 'v1.a'
  END;

  v_dyad_id := uuid_generate_v4();

  LOOP
    v_session_code := generate_session_code();
    EXIT WHEN NOT EXISTS (SELECT 1 FROM sessions WHERE sessions.session_code = v_session_code);
  END LOOP;

  v_treatment1 := 'payoff_always_visible';
  v_treatment2 := 'payoff_collapsible';

  INSERT INTO sessions (
    session_code, status, negotiation_scenario, time_limit_minutes,
    dyad_id, round_number, pair_session_id
  )
  VALUES (
    v_session_code, 'waiting', v_scenario, 10,
    v_dyad_id, p_round_number, p_pair_session_id
  )
  RETURNING id INTO v_session_id;

  INSERT INTO session_participants (session_id, participant_id, role, treatment_condition)
  VALUES
    (v_session_id, v_participant1_id, COALESCE(v_role1, 'pm'), v_treatment1),
    (v_session_id, v_participant2_id, COALESCE(v_role2, 'developer'), v_treatment2);

  RETURN v_session_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION create_round_for_pair IS 'Creates a round session for a pair; 10 min per round, payoff v1.a/b/c by round';


-- ============================================================
-- Migration 012: Batch Matchmaking (match_batch_for_round)
-- ============================================================

-- Batch matchmaking: match all queued participants for a round
CREATE OR REPLACE FUNCTION match_batch_for_round(p_batch_id UUID, p_slot_index INTEGER)
RETURNS INTEGER AS $$
DECLARE
    v_condition TEXT;
    v_sessions_created INTEGER := 0;
    v_participant_id UUID;
    v_partner_id UUID;
BEGIN
    IF p_slot_index < 1 OR p_slot_index > 3 THEN
        RAISE EXCEPTION 'slot_index must be 1, 2, or 3';
    END IF;

    CREATE TEMP TABLE IF NOT EXISTS batch_match_queued (
        participant_id UUID PRIMARY KEY,
        condition TEXT NOT NULL
    );
    DELETE FROM batch_match_queued WHERE TRUE;

    INSERT INTO batch_match_queued (participant_id, condition)
    SELECT rq.participant_id, (bp.condition_order->>(p_slot_index - 1))::TEXT
    FROM round_queue rq
    JOIN batch_participants bp ON bp.participant_id = rq.participant_id AND bp.batch_id = p_batch_id
    WHERE rq.round_number = p_slot_index
    FOR UPDATE OF rq;

    CREATE TEMP TABLE IF NOT EXISTS batch_match_remaining (
        participant_id UUID PRIMARY KEY
    );

    FOR v_condition IN SELECT DISTINCT condition FROM batch_match_queued
    LOOP
        DELETE FROM batch_match_remaining WHERE TRUE;
        INSERT INTO batch_match_remaining (participant_id)
        SELECT participant_id FROM batch_match_queued WHERE condition = v_condition;

        WHILE (SELECT COUNT(*) FROM batch_match_remaining) > 0 LOOP
            SELECT r.participant_id INTO v_participant_id
            FROM batch_match_remaining r
            ORDER BY (
                SELECT COUNT(*)
                FROM batch_match_remaining r2
                WHERE r2.participant_id <> r.participant_id
                  AND NOT EXISTS (
                      SELECT 1
                      FROM session_participants sp1
                      JOIN session_participants sp2 ON sp1.session_id = sp2.session_id AND sp2.participant_id = r2.participant_id
                      JOIN sessions s ON s.id = sp1.session_id
                      WHERE sp1.participant_id = r.participant_id
                        AND s.round_number IS NOT NULL
                        AND s.round_number < p_slot_index
                  )
            ), r.participant_id
            LIMIT 1;

            IF v_participant_id IS NULL THEN
                RAISE EXCEPTION 'match_batch_for_round: no participant in remaining (logic error)';
            END IF;

            SELECT r2.participant_id INTO v_partner_id
            FROM batch_match_remaining r2
            WHERE r2.participant_id <> v_participant_id
              AND NOT EXISTS (
                  SELECT 1
                  FROM session_participants sp1
                  JOIN session_participants sp2 ON sp1.session_id = sp2.session_id AND sp2.participant_id = r2.participant_id
                  JOIN sessions s ON s.id = sp1.session_id
                  WHERE sp1.participant_id = v_participant_id
                    AND s.round_number IS NOT NULL
                    AND s.round_number < p_slot_index
              )
            ORDER BY r2.participant_id
            LIMIT 1;

            IF v_partner_id IS NULL THEN
                RAISE EXCEPTION 'match_batch_for_round: no valid partner for participant % in condition % (odd bucket or past-opponent deadlock)',
                    v_participant_id, v_condition;
            END IF;

            PERFORM create_one_pool_session(v_participant_id, v_partner_id, p_slot_index, v_condition);

            v_sessions_created := v_sessions_created + 1;

            DELETE FROM round_queue
            WHERE participant_id IN (v_participant_id, v_partner_id) AND round_number = p_slot_index;

            DELETE FROM batch_match_remaining
            WHERE participant_id IN (v_participant_id, v_partner_id);
        END LOOP;
    END LOOP;

    RETURN v_sessions_created;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION match_batch_for_round IS 'Batch matchmaking: match all queued participants for a round (same condition, no past opponent); returns sessions created';

-- Helper: create one pool session for two participants
CREATE OR REPLACE FUNCTION create_one_pool_session(
    p_participant_id UUID,
    p_partner_id UUID,
    p_slot_index INTEGER,
    p_condition TEXT
) RETURNS UUID AS $$
DECLARE
    v_dyad_id UUID;
    v_session_code TEXT;
    v_session_id UUID;
BEGIN
    v_dyad_id := uuid_generate_v4();

    LOOP
        v_session_code := generate_session_code();
        EXIT WHEN NOT EXISTS (SELECT 1 FROM sessions WHERE session_code = v_session_code)
          AND NOT EXISTS (SELECT 1 FROM experiment_batches WHERE batch_code = v_session_code);
    END LOOP;

    INSERT INTO sessions (
        session_code, status, negotiation_scenario, time_limit_minutes,
        dyad_id, round_number
    )
    VALUES (
        v_session_code, 'waiting', p_condition, 10,
        v_dyad_id, p_slot_index
    )
    RETURNING id INTO v_session_id;

    INSERT INTO session_participants (session_id, participant_id, role, treatment_condition)
    VALUES
        (v_session_id, p_participant_id, 'pm', 'payoff_always_visible'),
        (v_session_id, p_partner_id, 'developer', 'payoff_collapsible');

    RETURN v_session_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION create_one_pool_session IS 'Creates one pool round session for two participants; used by match_batch_for_round';


-- ============================================================
-- Migration 013: Batch Round Queue Counts
-- ============================================================

CREATE OR REPLACE FUNCTION get_batch_round_queue_counts(p_batch_ids UUID[])
RETURNS TABLE(batch_id UUID, round_number INTEGER, queue_count BIGINT) AS $$
BEGIN
    RETURN QUERY
    SELECT bp.batch_id,
           rq.round_number::INTEGER,
           COUNT(*)::BIGINT
    FROM round_queue rq
    JOIN batch_participants bp ON bp.participant_id = rq.participant_id
    WHERE bp.batch_id = ANY(p_batch_ids)
      AND rq.round_number BETWEEN 1 AND 3
    GROUP BY bp.batch_id, rq.round_number;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER STABLE;

COMMENT ON FUNCTION get_batch_round_queue_counts IS 'Returns queue counts per (batch_id, round_number) for admin and auto-match';


-- ============================================================
-- Migration 014: Clear Batches and Round Sessions
-- ============================================================

CREATE OR REPLACE FUNCTION clear_all_batches_and_round_sessions()
RETURNS TABLE(sessions_deleted BIGINT, queue_deleted BIGINT, batches_deleted BIGINT) AS $$
DECLARE
    v_sessions BIGINT;
    v_queue BIGINT;
    v_batches BIGINT;
BEGIN
    WITH deleted AS (
        DELETE FROM sessions WHERE round_number IS NOT NULL RETURNING id
    )
    SELECT COUNT(*)::BIGINT INTO v_sessions FROM deleted;

    WITH deleted AS (
        DELETE FROM round_queue WHERE TRUE RETURNING id
    )
    SELECT COUNT(*)::BIGINT INTO v_queue FROM deleted;

    WITH deleted AS (
        DELETE FROM experiment_batches WHERE TRUE RETURNING id
    )
    SELECT COUNT(*)::BIGINT INTO v_batches FROM deleted;

    sessions_deleted := v_sessions;
    queue_deleted := v_queue;
    batches_deleted := v_batches;
    RETURN NEXT;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION clear_all_batches_and_round_sessions IS 'Cleanup: remove all batches, round sessions, and round queue for a fresh start. Leaves participants and non-round sessions intact.';


-- ============================================================
-- Migration 015: Match Batch - Odd Bucket and Guard
-- Excludes already-matched; leaves odd-condition participants in queue
-- ============================================================

CREATE OR REPLACE FUNCTION match_batch_for_round(p_batch_id UUID, p_slot_index INTEGER)
RETURNS INTEGER AS $$
DECLARE
    v_condition TEXT;
    v_sessions_created INTEGER := 0;
    v_participant_id UUID;
    v_partner_id UUID;
BEGIN
    IF p_slot_index < 1 OR p_slot_index > 3 THEN
        RAISE EXCEPTION 'slot_index must be 1, 2, or 3';
    END IF;

    CREATE TEMP TABLE IF NOT EXISTS batch_match_queued (
        participant_id UUID PRIMARY KEY,
        condition TEXT NOT NULL
    );
    DELETE FROM batch_match_queued WHERE TRUE;

    INSERT INTO batch_match_queued (participant_id, condition)
    SELECT rq.participant_id, (bp.condition_order->>(p_slot_index - 1))::TEXT
    FROM round_queue rq
    JOIN batch_participants bp ON bp.participant_id = rq.participant_id AND bp.batch_id = p_batch_id
    WHERE rq.round_number = p_slot_index
      AND NOT EXISTS (
          SELECT 1
          FROM session_participants sp
          JOIN sessions s ON s.id = sp.session_id
          WHERE sp.participant_id = rq.participant_id
            AND s.round_number = p_slot_index
      )
    FOR UPDATE OF rq;

    CREATE TEMP TABLE IF NOT EXISTS batch_match_remaining (
        participant_id UUID PRIMARY KEY
    );

    FOR v_condition IN SELECT DISTINCT condition FROM batch_match_queued
    LOOP
        DELETE FROM batch_match_remaining WHERE TRUE;
        INSERT INTO batch_match_remaining (participant_id)
        SELECT participant_id FROM batch_match_queued WHERE condition = v_condition;

        WHILE (SELECT COUNT(*) FROM batch_match_remaining) > 0 LOOP
            SELECT r.participant_id INTO v_participant_id
            FROM batch_match_remaining r
            ORDER BY (
                SELECT COUNT(*)
                FROM batch_match_remaining r2
                WHERE r2.participant_id <> r.participant_id
                  AND NOT EXISTS (
                      SELECT 1
                      FROM session_participants sp1
                      JOIN session_participants sp2 ON sp1.session_id = sp2.session_id AND sp2.participant_id = r2.participant_id
                      JOIN sessions s ON s.id = sp1.session_id
                      WHERE sp1.participant_id = r.participant_id
                        AND s.round_number IS NOT NULL
                        AND s.round_number < p_slot_index
                  )
            ), r.participant_id
            LIMIT 1;

            IF v_participant_id IS NULL THEN
                EXIT;
            END IF;

            SELECT r2.participant_id INTO v_partner_id
            FROM batch_match_remaining r2
            WHERE r2.participant_id <> v_participant_id
              AND NOT EXISTS (
                  SELECT 1
                  FROM session_participants sp1
                  JOIN session_participants sp2 ON sp1.session_id = sp2.session_id AND sp2.participant_id = r2.participant_id
                  JOIN sessions s ON s.id = sp1.session_id
                  WHERE sp1.participant_id = v_participant_id
                    AND s.round_number IS NOT NULL
                    AND s.round_number < p_slot_index
              )
            ORDER BY r2.participant_id
            LIMIT 1;

            IF v_partner_id IS NULL THEN
                DELETE FROM batch_match_remaining WHERE participant_id = v_participant_id;
                CONTINUE;
            END IF;

            PERFORM create_one_pool_session(v_participant_id, v_partner_id, p_slot_index, v_condition);
            v_sessions_created := v_sessions_created + 1;

            DELETE FROM round_queue
            WHERE participant_id IN (v_participant_id, v_partner_id) AND round_number = p_slot_index;

            DELETE FROM batch_match_remaining
            WHERE participant_id IN (v_participant_id, v_partner_id);
        END LOOP;
    END LOOP;

    RETURN v_sessions_created;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION match_batch_for_round IS 'Batch matchmaking: match queued participants for a round (same condition, no past opponent). Skips already-matched; leaves odd-condition participants in queue instead of failing.';


-- ============================================================
-- Migration 016: Join Batch Atomic
-- Atomic batch join with paired condition assignment
-- ============================================================

CREATE OR REPLACE FUNCTION join_batch_atomic(p_batch_id UUID, p_participant_id UUID)
RETURNS batch_participants AS $$
DECLARE
    v_batch experiment_batches;
    v_count INTEGER;
    v_perm_index INTEGER;
    v_condition_order JSONB;
    v_row batch_participants;
BEGIN
    SELECT * INTO v_batch
    FROM experiment_batches
    WHERE id = p_batch_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Batch not found';
    END IF;
    IF v_batch.status <> 'open' THEN
        RAISE EXCEPTION 'Batch is not open for joining';
    END IF;

    SELECT * INTO v_row
    FROM batch_participants
    WHERE batch_id = p_batch_id AND participant_id = p_participant_id;
    IF FOUND THEN
        RETURN v_row;
    END IF;

    v_count := (SELECT count(*)::INTEGER FROM batch_participants WHERE batch_id = p_batch_id);
    IF v_count >= v_batch.max_participants THEN
        RAISE EXCEPTION 'Batch is full';
    END IF;

    v_perm_index := (v_count / 2) % 6;

    v_condition_order := CASE v_perm_index
        WHEN 0 THEN '["v1.a","v1.b","v1.c"]'::JSONB
        WHEN 1 THEN '["v1.a","v1.c","v1.b"]'::JSONB
        WHEN 2 THEN '["v1.b","v1.a","v1.c"]'::JSONB
        WHEN 3 THEN '["v1.b","v1.c","v1.a"]'::JSONB
        WHEN 4 THEN '["v1.c","v1.a","v1.b"]'::JSONB
        ELSE '["v1.c","v1.b","v1.a"]'::JSONB
    END;

    INSERT INTO batch_participants (batch_id, participant_id, condition_order)
    VALUES (p_batch_id, p_participant_id, v_condition_order)
    RETURNING * INTO v_row;

    RETURN v_row;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION join_batch_atomic IS 'Atomic batch join: assigns condition order in pairs so every round has even condition counts; prevents one participant left waiting when many join at once.';


-- ============================================================
-- Migration 017: Match Batch Cross-Condition Pair
-- Pairs remaining 2 from different conditions so no one waits
-- ============================================================

CREATE OR REPLACE FUNCTION match_batch_for_round(p_batch_id UUID, p_slot_index INTEGER)
RETURNS INTEGER AS $$
DECLARE
    v_condition TEXT;
    v_sessions_created INTEGER := 0;
    v_participant_id UUID;
    v_partner_id UUID;
    v_remain_count INTEGER;
    v_p1_id UUID;
    v_p2_id UUID;
    v_p1_condition TEXT;
BEGIN
    IF p_slot_index < 1 OR p_slot_index > 3 THEN
        RAISE EXCEPTION 'slot_index must be 1, 2, or 3';
    END IF;

    CREATE TEMP TABLE IF NOT EXISTS batch_match_queued (
        participant_id UUID PRIMARY KEY,
        condition TEXT NOT NULL
    );
    DELETE FROM batch_match_queued WHERE TRUE;

    INSERT INTO batch_match_queued (participant_id, condition)
    SELECT rq.participant_id, (bp.condition_order->>(p_slot_index - 1))::TEXT
    FROM round_queue rq
    JOIN batch_participants bp ON bp.participant_id = rq.participant_id AND bp.batch_id = p_batch_id
    WHERE rq.round_number = p_slot_index
      AND NOT EXISTS (
          SELECT 1
          FROM session_participants sp
          JOIN sessions s ON s.id = sp.session_id
          WHERE sp.participant_id = rq.participant_id
            AND s.round_number = p_slot_index
      )
    FOR UPDATE OF rq;

    CREATE TEMP TABLE IF NOT EXISTS batch_match_remaining (
        participant_id UUID PRIMARY KEY
    );

    FOR v_condition IN SELECT DISTINCT condition FROM batch_match_queued
    LOOP
        DELETE FROM batch_match_remaining WHERE TRUE;
        INSERT INTO batch_match_remaining (participant_id)
        SELECT participant_id FROM batch_match_queued WHERE condition = v_condition;

        WHILE (SELECT COUNT(*) FROM batch_match_remaining) > 0 LOOP
            SELECT r.participant_id INTO v_participant_id
            FROM batch_match_remaining r
            ORDER BY (
                SELECT COUNT(*)
                FROM batch_match_remaining r2
                WHERE r2.participant_id <> r.participant_id
                  AND NOT EXISTS (
                      SELECT 1
                      FROM session_participants sp1
                      JOIN session_participants sp2 ON sp1.session_id = sp2.session_id AND sp2.participant_id = r2.participant_id
                      JOIN sessions s ON s.id = sp1.session_id
                      WHERE sp1.participant_id = r.participant_id
                        AND s.round_number IS NOT NULL
                        AND s.round_number < p_slot_index
                  )
            ), r.participant_id
            LIMIT 1;

            IF v_participant_id IS NULL THEN
                EXIT;
            END IF;

            SELECT r2.participant_id INTO v_partner_id
            FROM batch_match_remaining r2
            WHERE r2.participant_id <> v_participant_id
              AND NOT EXISTS (
                  SELECT 1
                  FROM session_participants sp1
                  JOIN session_participants sp2 ON sp1.session_id = sp2.session_id AND sp2.participant_id = r2.participant_id
                  JOIN sessions s ON s.id = sp1.session_id
                  WHERE sp1.participant_id = v_participant_id
                    AND s.round_number IS NOT NULL
                    AND s.round_number < p_slot_index
              )
            ORDER BY r2.participant_id
            LIMIT 1;

            IF v_partner_id IS NULL THEN
                DELETE FROM batch_match_remaining WHERE participant_id = v_participant_id;
                CONTINUE;
            END IF;

            PERFORM create_one_pool_session(v_participant_id, v_partner_id, p_slot_index, v_condition);
            v_sessions_created := v_sessions_created + 1;

            DELETE FROM round_queue
            WHERE participant_id IN (v_participant_id, v_partner_id) AND round_number = p_slot_index;

            DELETE FROM batch_match_remaining
            WHERE participant_id IN (v_participant_id, v_partner_id);
        END LOOP;
    END LOOP;

    -- Cross-condition pair: if exactly 2 remain in queue for this batch+round, pair them
    SELECT count(*)::INTEGER INTO v_remain_count
    FROM round_queue rq
    JOIN batch_participants bp ON bp.participant_id = rq.participant_id AND bp.batch_id = p_batch_id
    WHERE rq.round_number = p_slot_index;

    IF v_remain_count = 2 THEN
        SELECT rq.participant_id, (bp.condition_order->>(p_slot_index - 1))::TEXT
        INTO v_p1_id, v_p1_condition
        FROM round_queue rq
        JOIN batch_participants bp ON bp.participant_id = rq.participant_id AND bp.batch_id = p_batch_id
        WHERE rq.round_number = p_slot_index
        ORDER BY rq.participant_id
        LIMIT 1;

        SELECT rq.participant_id INTO v_p2_id
        FROM round_queue rq
        JOIN batch_participants bp ON bp.participant_id = rq.participant_id AND bp.batch_id = p_batch_id
        WHERE rq.round_number = p_slot_index AND rq.participant_id <> v_p1_id
        LIMIT 1;

        IF v_p2_id IS NOT NULL AND NOT EXISTS (
            SELECT 1
            FROM session_participants sp1
            JOIN session_participants sp2 ON sp1.session_id = sp2.session_id AND sp2.participant_id = v_p2_id
            JOIN sessions s ON s.id = sp1.session_id
            WHERE sp1.participant_id = v_p1_id
              AND s.round_number IS NOT NULL
              AND s.round_number < p_slot_index
        ) THEN
            PERFORM create_one_pool_session(v_p1_id, v_p2_id, p_slot_index, v_p1_condition);
            v_sessions_created := v_sessions_created + 1;
            DELETE FROM round_queue
            WHERE participant_id IN (v_p1_id, v_p2_id) AND round_number = p_slot_index;
        END IF;
    END IF;

    RETURN v_sessions_created;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION match_batch_for_round IS 'Batch matchmaking: same-condition pairs first; if exactly 2 remain (odd from different conditions), pair them in one cross-condition session so no one is left waiting.';


-- ============================================================
-- Migration 018: Pre-Seeded Round Schedule
-- ============================================================

CREATE TABLE IF NOT EXISTS batch_round_assignments (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    batch_id UUID NOT NULL REFERENCES experiment_batches(id) ON DELETE CASCADE,
    round_number INTEGER NOT NULL CHECK (round_number >= 1 AND round_number <= 3),
    participant_id_1 UUID NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
    participant_id_2 UUID NOT NULL REFERENCES participants(id) ON DELETE CASCADE,
    CONSTRAINT batch_round_assignments_order CHECK (participant_id_1 < participant_id_2),
    UNIQUE (batch_id, round_number, participant_id_1),
    UNIQUE (batch_id, round_number, participant_id_2)
);

COMMENT ON TABLE batch_round_assignments IS 'Pre-seeded round schedule: who meets whom each round; no repeat opponents. Generated when batch reaches 18.';
CREATE INDEX IF NOT EXISTS idx_batch_round_assignments_batch_round ON batch_round_assignments(batch_id, round_number);
CREATE INDEX IF NOT EXISTS idx_batch_round_assignments_participant ON batch_round_assignments(batch_id, round_number, participant_id_1);
CREATE INDEX IF NOT EXISTS idx_batch_round_assignments_p2 ON batch_round_assignments(batch_id, round_number, participant_id_2);

-- Generate round schedule for 18 participants (circle method)
CREATE OR REPLACE FUNCTION generate_batch_round_schedule(p_batch_id UUID)
RETURNS VOID AS $$
DECLARE
    v_count INTEGER;
    v_participant_ids UUID[] := '{}';
    v_i INTEGER;
    v_j INTEGER;
    v_p1 UUID;
    v_p2 UUID;
BEGIN
    SELECT count(*)::INTEGER INTO v_count
    FROM batch_participants WHERE batch_id = p_batch_id;

    IF v_count <> 18 THEN
        RETURN;
    END IF;

    IF EXISTS (SELECT 1 FROM batch_round_assignments WHERE batch_id = p_batch_id LIMIT 1) THEN
        RETURN;
    END IF;

    SELECT array_agg(participant_id ORDER BY joined_at, id)
    INTO v_participant_ids
    FROM batch_participants
    WHERE batch_id = p_batch_id;

    IF array_length(v_participant_ids, 1) <> 18 THEN
        RETURN;
    END IF;

    -- Round 1: (17,0),(1,16),(2,15),(3,14),(4,13),(5,12),(6,11),(7,10),(8,9)
    INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
    VALUES
        (p_batch_id, 1, LEAST(v_participant_ids[18], v_participant_ids[1]), GREATEST(v_participant_ids[18], v_participant_ids[1])),
        (p_batch_id, 1, LEAST(v_participant_ids[2], v_participant_ids[17]), GREATEST(v_participant_ids[2], v_participant_ids[17])),
        (p_batch_id, 1, LEAST(v_participant_ids[3], v_participant_ids[16]), GREATEST(v_participant_ids[3], v_participant_ids[16])),
        (p_batch_id, 1, LEAST(v_participant_ids[4], v_participant_ids[15]), GREATEST(v_participant_ids[4], v_participant_ids[15])),
        (p_batch_id, 1, LEAST(v_participant_ids[5], v_participant_ids[14]), GREATEST(v_participant_ids[5], v_participant_ids[14])),
        (p_batch_id, 1, LEAST(v_participant_ids[6], v_participant_ids[13]), GREATEST(v_participant_ids[6], v_participant_ids[13])),
        (p_batch_id, 1, LEAST(v_participant_ids[7], v_participant_ids[12]), GREATEST(v_participant_ids[7], v_participant_ids[12])),
        (p_batch_id, 1, LEAST(v_participant_ids[8], v_participant_ids[11]), GREATEST(v_participant_ids[8], v_participant_ids[11])),
        (p_batch_id, 1, LEAST(v_participant_ids[9], v_participant_ids[10]), GREATEST(v_participant_ids[9], v_participant_ids[10]));

    -- Round 2: (17,1),(2,0),(3,16),(4,15),(5,14),(6,13),(7,12),(8,11),(9,10)
    INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
    VALUES
        (p_batch_id, 2, LEAST(v_participant_ids[18], v_participant_ids[2]), GREATEST(v_participant_ids[18], v_participant_ids[2])),
        (p_batch_id, 2, LEAST(v_participant_ids[3], v_participant_ids[1]), GREATEST(v_participant_ids[3], v_participant_ids[1])),
        (p_batch_id, 2, LEAST(v_participant_ids[4], v_participant_ids[17]), GREATEST(v_participant_ids[4], v_participant_ids[17])),
        (p_batch_id, 2, LEAST(v_participant_ids[5], v_participant_ids[16]), GREATEST(v_participant_ids[5], v_participant_ids[16])),
        (p_batch_id, 2, LEAST(v_participant_ids[6], v_participant_ids[15]), GREATEST(v_participant_ids[6], v_participant_ids[15])),
        (p_batch_id, 2, LEAST(v_participant_ids[7], v_participant_ids[14]), GREATEST(v_participant_ids[7], v_participant_ids[14])),
        (p_batch_id, 2, LEAST(v_participant_ids[8], v_participant_ids[13]), GREATEST(v_participant_ids[8], v_participant_ids[13])),
        (p_batch_id, 2, LEAST(v_participant_ids[9], v_participant_ids[12]), GREATEST(v_participant_ids[9], v_participant_ids[12])),
        (p_batch_id, 2, LEAST(v_participant_ids[10], v_participant_ids[11]), GREATEST(v_participant_ids[10], v_participant_ids[11]));

    -- Round 3: (17,2),(3,1),(4,0),(5,16),(6,15),(7,14),(8,13),(9,12),(10,11)
    INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
    VALUES
        (p_batch_id, 3, LEAST(v_participant_ids[18], v_participant_ids[3]), GREATEST(v_participant_ids[18], v_participant_ids[3])),
        (p_batch_id, 3, LEAST(v_participant_ids[4], v_participant_ids[2]), GREATEST(v_participant_ids[4], v_participant_ids[2])),
        (p_batch_id, 3, LEAST(v_participant_ids[5], v_participant_ids[1]), GREATEST(v_participant_ids[5], v_participant_ids[1])),
        (p_batch_id, 3, LEAST(v_participant_ids[6], v_participant_ids[17]), GREATEST(v_participant_ids[6], v_participant_ids[17])),
        (p_batch_id, 3, LEAST(v_participant_ids[7], v_participant_ids[16]), GREATEST(v_participant_ids[7], v_participant_ids[16])),
        (p_batch_id, 3, LEAST(v_participant_ids[8], v_participant_ids[15]), GREATEST(v_participant_ids[8], v_participant_ids[15])),
        (p_batch_id, 3, LEAST(v_participant_ids[9], v_participant_ids[14]), GREATEST(v_participant_ids[9], v_participant_ids[14])),
        (p_batch_id, 3, LEAST(v_participant_ids[10], v_participant_ids[13]), GREATEST(v_participant_ids[10], v_participant_ids[13])),
        (p_batch_id, 3, LEAST(v_participant_ids[11], v_participant_ids[12]), GREATEST(v_participant_ids[11], v_participant_ids[12]));

END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION generate_batch_round_schedule IS 'Pre-seed round schedule for 18 participants (circle method); idempotent.';

-- Pre-seeded flow: look up partner, create session when both in queue
CREATE OR REPLACE FUNCTION get_or_create_round_session(
    p_batch_id UUID,
    p_participant_id UUID,
    p_round_number INTEGER
)
RETURNS TABLE(session_id UUID, session_code TEXT, role TEXT, dyad_id UUID) AS $$
DECLARE
    v_partner_id UUID;
    v_condition TEXT;
    v_session_id UUID;
    v_session_code TEXT;
    v_dyad_id UUID;
    v_my_role TEXT;
BEGIN
    IF p_round_number < 1 OR p_round_number > 3 THEN
        RETURN;
    END IF;

    SELECT CASE
        WHEN bra.participant_id_1 = p_participant_id THEN bra.participant_id_2
        ELSE bra.participant_id_1
    END INTO v_partner_id
    FROM batch_round_assignments bra
    WHERE bra.batch_id = p_batch_id AND bra.round_number = p_round_number
      AND (bra.participant_id_1 = p_participant_id OR bra.participant_id_2 = p_participant_id);

    IF v_partner_id IS NULL THEN
        RETURN;
    END IF;

    INSERT INTO round_queue (participant_id, round_number)
    VALUES (p_participant_id, p_round_number)
    ON CONFLICT (participant_id, round_number) DO NOTHING;

    -- Session already exists for this pair + round?
    SELECT s.id, s.session_code, s.dyad_id INTO v_session_id, v_session_code, v_dyad_id
    FROM sessions s
    JOIN session_participants sp1 ON sp1.session_id = s.id AND sp1.participant_id = p_participant_id
    JOIN session_participants sp2 ON sp2.session_id = s.id AND sp2.participant_id = v_partner_id
    WHERE s.round_number = p_round_number
    LIMIT 1;

    IF v_session_id IS NOT NULL THEN
        SELECT sp.role INTO v_my_role FROM session_participants sp WHERE sp.session_id = v_session_id AND sp.participant_id = p_participant_id;
        session_id := v_session_id;
        session_code := v_session_code;
        role := v_my_role;
        dyad_id := v_dyad_id;
        RETURN NEXT;
        RETURN;
    END IF;

    -- Partner in queue?
    IF NOT EXISTS (SELECT 1 FROM round_queue WHERE participant_id = v_partner_id AND round_number = p_round_number) THEN
        RETURN;
    END IF;

    PERFORM 1 FROM round_queue
    WHERE (participant_id = p_participant_id OR participant_id = v_partner_id) AND round_number = p_round_number
    FOR UPDATE;

    -- Re-check (other transaction may have just created it)
    SELECT s.id INTO v_session_id
    FROM sessions s
    JOIN session_participants sp1 ON sp1.session_id = s.id AND sp1.participant_id = p_participant_id
    JOIN session_participants sp2 ON sp2.session_id = s.id AND sp2.participant_id = v_partner_id
    WHERE s.round_number = p_round_number LIMIT 1;
    IF v_session_id IS NOT NULL THEN
        SELECT s.session_code, s.dyad_id INTO v_session_code, v_dyad_id FROM sessions s WHERE s.id = v_session_id;
        SELECT sp.role INTO v_my_role FROM session_participants sp WHERE sp.session_id = v_session_id AND sp.participant_id = p_participant_id;
        session_id := v_session_id;
        session_code := v_session_code;
        role := v_my_role;
        dyad_id := v_dyad_id;
        RETURN NEXT;
        RETURN;
    END IF;

    -- Use first participant's condition for this round (deterministic)
    SELECT (bp.condition_order->>(p_round_number - 1))::TEXT INTO v_condition
    FROM batch_participants bp
    WHERE bp.batch_id = p_batch_id AND bp.participant_id = LEAST(p_participant_id, v_partner_id)
    LIMIT 1;

    IF v_condition IS NULL OR v_condition = '' THEN
        v_condition := 'v1.a';
    END IF;

    v_session_id := create_one_pool_session(
        LEAST(p_participant_id, v_partner_id)::UUID,
        GREATEST(p_participant_id, v_partner_id)::UUID,
        p_round_number,
        v_condition
    );

    DELETE FROM round_queue
    WHERE (participant_id = p_participant_id OR participant_id = v_partner_id) AND round_number = p_round_number;

    SELECT s.session_code, s.dyad_id INTO v_session_code, v_dyad_id FROM sessions s WHERE s.id = v_session_id;
    SELECT sp.role INTO v_my_role FROM session_participants sp WHERE sp.session_id = v_session_id AND sp.participant_id = p_participant_id;

    session_id := v_session_id;
    session_code := v_session_code;
    role := v_my_role;
    dyad_id := v_dyad_id;
    RETURN NEXT;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION get_or_create_round_session IS 'Pre-seeded flow: look up partner, create session when both in queue; returns session+role or null.';


-- ============================================================
-- Migration 019: Join Batch Generate Schedule
-- When 18th participant joins, auto-generate the pre-seeded schedule
-- ============================================================

CREATE OR REPLACE FUNCTION join_batch_atomic(p_batch_id UUID, p_participant_id UUID)
RETURNS batch_participants AS $$
DECLARE
    v_batch experiment_batches;
    v_count INTEGER;
    v_perm_index INTEGER;
    v_condition_order JSONB;
    v_row batch_participants;
BEGIN
    SELECT * INTO v_batch
    FROM experiment_batches
    WHERE id = p_batch_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Batch not found';
    END IF;
    IF v_batch.status <> 'open' THEN
        RAISE EXCEPTION 'Batch is not open for joining';
    END IF;

    SELECT * INTO v_row
    FROM batch_participants
    WHERE batch_id = p_batch_id AND participant_id = p_participant_id;
    IF FOUND THEN
        RETURN v_row;
    END IF;

    v_count := (SELECT count(*)::INTEGER FROM batch_participants WHERE batch_id = p_batch_id);
    IF v_count >= v_batch.max_participants THEN
        RAISE EXCEPTION 'Batch is full';
    END IF;

    v_perm_index := (v_count / 2) % 6;
    v_condition_order := CASE v_perm_index
        WHEN 0 THEN '["v1.a","v1.b","v1.c"]'::JSONB
        WHEN 1 THEN '["v1.a","v1.c","v1.b"]'::JSONB
        WHEN 2 THEN '["v1.b","v1.a","v1.c"]'::JSONB
        WHEN 3 THEN '["v1.b","v1.c","v1.a"]'::JSONB
        WHEN 4 THEN '["v1.c","v1.a","v1.b"]'::JSONB
        ELSE '["v1.c","v1.b","v1.a"]'::JSONB
    END;

    INSERT INTO batch_participants (batch_id, participant_id, condition_order)
    VALUES (p_batch_id, p_participant_id, v_condition_order)
    RETURNING * INTO v_row;

    -- Pre-seed round schedule when batch reaches max (e.g. 18)
    IF (v_count + 1) = v_batch.max_participants THEN
        PERFORM generate_batch_round_schedule(p_batch_id);
    END IF;

    RETURN v_row;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION join_batch_atomic IS 'Atomic batch join; when 18th joins, generates pre-seeded round schedule.';


-- ============================================================
-- Migration 020: Add to Round Queue RPC
-- ============================================================

CREATE OR REPLACE FUNCTION add_to_round_queue(p_participant_id UUID, p_round_number INTEGER)
RETURNS VOID AS $$
BEGIN
    IF p_round_number < 1 OR p_round_number > 3 THEN
        RETURN;
    END IF;
    INSERT INTO round_queue (participant_id, round_number)
    VALUES (p_participant_id, p_round_number)
    ON CONFLICT (participant_id, round_number) DO NOTHING;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION add_to_round_queue IS 'Idempotent: add participant to round queue (e.g. when lobby page loads so first poll can match).';


-- ============================================================
-- Migration 021: Batch Has Schedule
-- ============================================================

CREATE OR REPLACE FUNCTION batch_has_schedule(p_batch_id UUID)
RETURNS BOOLEAN AS $$
BEGIN
    RETURN EXISTS (SELECT 1 FROM batch_round_assignments WHERE batch_id = p_batch_id LIMIT 1);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER STABLE;

COMMENT ON FUNCTION batch_has_schedule IS 'True if this batch has pre-seeded round assignments; lobby should not use condition-based fallback when true.';


-- ============================================================
-- Migration 022: Test Batch Six Participants
-- Support pre-seeded schedule for 6 participants (test batch)
-- ============================================================

CREATE OR REPLACE FUNCTION generate_batch_round_schedule(p_batch_id UUID)
RETURNS VOID AS $$
DECLARE
    v_count INTEGER;
    v_participant_ids UUID[] := '{}';
BEGIN
    SELECT count(*)::INTEGER INTO v_count
    FROM batch_participants WHERE batch_id = p_batch_id;

    IF v_count NOT IN (6, 12, 18) THEN
        RETURN;
    END IF;

    IF EXISTS (SELECT 1 FROM batch_round_assignments WHERE batch_id = p_batch_id LIMIT 1) THEN
        RETURN;
    END IF;

    SELECT array_agg(participant_id ORDER BY joined_at, id)
    INTO v_participant_ids
    FROM batch_participants
    WHERE batch_id = p_batch_id;

    IF array_length(v_participant_ids, 1) IS NULL OR array_length(v_participant_ids, 1) <> v_count THEN
        RETURN;
    END IF;

    -- ========== 6 participants (test batch): 3 pairs per round ==========
    IF v_count = 6 THEN
        -- Round 1: (1,6),(2,5),(3,4)
        INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
        VALUES
            (p_batch_id, 1, LEAST(v_participant_ids[1], v_participant_ids[6]), GREATEST(v_participant_ids[1], v_participant_ids[6])),
            (p_batch_id, 1, LEAST(v_participant_ids[2], v_participant_ids[5]), GREATEST(v_participant_ids[2], v_participant_ids[5])),
            (p_batch_id, 1, LEAST(v_participant_ids[3], v_participant_ids[4]), GREATEST(v_participant_ids[3], v_participant_ids[4]));
        -- Round 2: (2,6),(1,3),(4,5)
        INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
        VALUES
            (p_batch_id, 2, LEAST(v_participant_ids[2], v_participant_ids[6]), GREATEST(v_participant_ids[2], v_participant_ids[6])),
            (p_batch_id, 2, LEAST(v_participant_ids[1], v_participant_ids[3]), GREATEST(v_participant_ids[1], v_participant_ids[3])),
            (p_batch_id, 2, LEAST(v_participant_ids[4], v_participant_ids[5]), GREATEST(v_participant_ids[4], v_participant_ids[5]));
        -- Round 3: (3,6),(2,4),(1,5)
        INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
        VALUES
            (p_batch_id, 3, LEAST(v_participant_ids[3], v_participant_ids[6]), GREATEST(v_participant_ids[3], v_participant_ids[6])),
            (p_batch_id, 3, LEAST(v_participant_ids[2], v_participant_ids[4]), GREATEST(v_participant_ids[2], v_participant_ids[4])),
            (p_batch_id, 3, LEAST(v_participant_ids[1], v_participant_ids[5]), GREATEST(v_participant_ids[1], v_participant_ids[5]));
        RETURN;
    END IF;

    -- ========== 12 participants (medium batch): 6 pairs per round ==========
    -- Circle method: fix participant 12, rotate 1-11
    IF v_count = 12 THEN
        -- Round 1: (12,1),(2,11),(3,10),(4,9),(5,8),(6,7)
        INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
        VALUES
            (p_batch_id, 1, LEAST(v_participant_ids[12], v_participant_ids[1]), GREATEST(v_participant_ids[12], v_participant_ids[1])),
            (p_batch_id, 1, LEAST(v_participant_ids[2], v_participant_ids[11]), GREATEST(v_participant_ids[2], v_participant_ids[11])),
            (p_batch_id, 1, LEAST(v_participant_ids[3], v_participant_ids[10]), GREATEST(v_participant_ids[3], v_participant_ids[10])),
            (p_batch_id, 1, LEAST(v_participant_ids[4], v_participant_ids[9]), GREATEST(v_participant_ids[4], v_participant_ids[9])),
            (p_batch_id, 1, LEAST(v_participant_ids[5], v_participant_ids[8]), GREATEST(v_participant_ids[5], v_participant_ids[8])),
            (p_batch_id, 1, LEAST(v_participant_ids[6], v_participant_ids[7]), GREATEST(v_participant_ids[6], v_participant_ids[7]));
        -- Round 2: (12,2),(3,1),(4,11),(5,10),(6,9),(7,8)
        INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
        VALUES
            (p_batch_id, 2, LEAST(v_participant_ids[12], v_participant_ids[2]), GREATEST(v_participant_ids[12], v_participant_ids[2])),
            (p_batch_id, 2, LEAST(v_participant_ids[3], v_participant_ids[1]), GREATEST(v_participant_ids[3], v_participant_ids[1])),
            (p_batch_id, 2, LEAST(v_participant_ids[4], v_participant_ids[11]), GREATEST(v_participant_ids[4], v_participant_ids[11])),
            (p_batch_id, 2, LEAST(v_participant_ids[5], v_participant_ids[10]), GREATEST(v_participant_ids[5], v_participant_ids[10])),
            (p_batch_id, 2, LEAST(v_participant_ids[6], v_participant_ids[9]), GREATEST(v_participant_ids[6], v_participant_ids[9])),
            (p_batch_id, 2, LEAST(v_participant_ids[7], v_participant_ids[8]), GREATEST(v_participant_ids[7], v_participant_ids[8]));
        -- Round 3: (12,3),(4,2),(5,1),(6,11),(7,10),(8,9)
        INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
        VALUES
            (p_batch_id, 3, LEAST(v_participant_ids[12], v_participant_ids[3]), GREATEST(v_participant_ids[12], v_participant_ids[3])),
            (p_batch_id, 3, LEAST(v_participant_ids[4], v_participant_ids[2]), GREATEST(v_participant_ids[4], v_participant_ids[2])),
            (p_batch_id, 3, LEAST(v_participant_ids[5], v_participant_ids[1]), GREATEST(v_participant_ids[5], v_participant_ids[1])),
            (p_batch_id, 3, LEAST(v_participant_ids[6], v_participant_ids[11]), GREATEST(v_participant_ids[6], v_participant_ids[11])),
            (p_batch_id, 3, LEAST(v_participant_ids[7], v_participant_ids[10]), GREATEST(v_participant_ids[7], v_participant_ids[10])),
            (p_batch_id, 3, LEAST(v_participant_ids[8], v_participant_ids[9]), GREATEST(v_participant_ids[8], v_participant_ids[9]));
        RETURN;
    END IF;

    -- ========== 18 participants (full batch): 9 pairs per round ==========
    -- Round 1
    INSERT INTO batch_round_assignments (batch_id, round_number, participant_id_1, participant_id_2)
    VALUES
        (p_batch_id, 1, LEAST(v_participant_ids[18], v_participant_ids[1]), GREATEST(v_participant_ids[18], v_participant_ids[1])),
        (p_batch_id, 1, LEAST(v_participant_ids[2], v_participant_ids[17]), GREATEST(v_participant_ids[2], v_participant_ids[17])),
